-- ── external_list_full_data.sql ────────────────────────────────────────────────
-- Full list data from the Acclaim Lists spreadsheet.
-- Run AFTER external_list_entries_schema.sql and external_list_migrate.sql.
-- Films already in our DB (linked via migration) are skipped by ON CONFLICT DO NOTHING.

-- Step 1: Add a title-based unique index so NFR (unranked) entries deduplicate cleanly.
-- Dedup any existing NFR duplicates first (keep row with film_id if present).
DELETE FROM public.external_list_entries a
USING public.external_list_entries b
WHERE a.list_name = b.list_name
  AND a.title = b.title
  AND a.id < b.id
  AND (a.film_id IS NULL OR b.film_id IS NOT NULL);

CREATE UNIQUE INDEX IF NOT EXISTS idx_ele_list_title
  ON public.external_list_entries (list_name, title);

